(async function a(){try{let A=await fetch('programma.json'),b=await A.json(),d=document.querySelector('.diretta-subtitle'),f=document.getElementById('live-link');document.title=`Diretta · ${b.titolo} · ${b.luogo}`;let c=document.querySelector('.diretta-title');c&&(c.textContent=b.titolo);d&&(d.textContent=`${b.titolo} — ${b.sottotitolo}`||'');let e=await fetch('diretta.ref').then(r=>r.text());e?f.setAttribute('href',e):f.style.display='none'}catch(e){}})();
